import{_ as i,o as s,c as e,ak as l}from"./chunks/framework.BeryCWZe.js";const k=JSON.parse('{"title":"部署","description":"","frontmatter":{},"headers":[],"relativePath":"guide/deployment.md","filePath":"guide/deployment.md","lastUpdated":1777912925000}'),t={name:"guide/deployment.md"};function n(p,a,h,d,r,o){return s(),e("div",null,[...a[0]||(a[0]=[l(`<h1 id="部署" tabindex="-1">部署 <a class="header-anchor" href="#部署" aria-label="Permalink to “部署”">​</a></h1><p>Lolimeow 是 Valaxy 主题，部署方式跟随 Valaxy 项目本身。</p><p>主题不会限制部署平台。你可以部署到 GitHub Pages、Netlify、Vercel、Cloudflare Pages 或自己的服务器。</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>更完整的部署方式请参考 <a href="https://valaxy.site/guide/deploy" target="_blank" rel="noreferrer">Valaxy 部署文档</a>。</p></div><h2 id="构建站点" tabindex="-1">构建站点 <a class="header-anchor" href="#构建站点" aria-label="Permalink to “构建站点”">​</a></h2><p>在 Valaxy 博客项目中执行构建命令：</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-20" id="tab-21" checked><label data-title="pnpm" for="tab-21">pnpm</label><input type="radio" name="group-20" id="tab-22"><label data-title="npm" for="tab-22">npm</label><input type="radio" name="group-20" id="tab-23"><label data-title="yarn" for="tab-23">yarn</label></div><div class="blocks"><div class="language-bash active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div></div></div><p>构建完成后，Valaxy 会生成静态站点产物。部署时应上传构建产物目录，而不是直接上传源码目录。</p><h2 id="部署前检查" tabindex="-1">部署前检查 <a class="header-anchor" href="#部署前检查" aria-label="Permalink to “部署前检查”">​</a></h2><p>部署前建议确认：</p><ul><li><code>site.config.ts</code> 中已经配置正确的 <code>url</code></li><li><code>site.config.ts</code> 中已经显式配置 <code>timezone</code></li><li>文章中的图片路径可以在生产环境访问</li><li>如果使用搜索，已经启用 Fuse 本地搜索</li><li>如果使用评论，评论服务已经允许生产域名访问</li><li>如果需要自定义 404 页面，构建产物根目录中应存在 <code>404.html</code></li></ul><h2 id="_404-页面" tabindex="-1">404 页面 <a class="header-anchor" href="#_404-页面" aria-label="Permalink to “404 页面”">​</a></h2><p>Lolimeow 提供了主题内置的 <code>404</code> 布局，但 Valaxy 需要站点侧存在一个实际页面，静态托管平台才会在构建产物中拿到根目录的 <code>404.html</code>。</p><p>在你的 Valaxy 博客项目中添加：</p><div class="language-md"><button title="Copy Code" class="copy"></button><span class="lang">md</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">---</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">layout: 404</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">---</span></span></code></pre></div><p>然后重新构建站点，确认构建产物目录中生成了 <code>404.html</code>。</p><p>GitHub Pages 和 Cloudflare Pages 会优先读取发布根目录下的 <code>404.html</code> 作为自定义 404 页面。如果没有这个文件，平台会显示默认 404 页面，而不是主题的 404 页面。</p><h2 id="github-pages" tabindex="-1">GitHub Pages <a class="header-anchor" href="#github-pages" aria-label="Permalink to “GitHub Pages”">​</a></h2><p>GitHub Pages 是常见的静态站点部署方式。</p><p>通常你需要：</p><ol><li>在仓库中添加 GitHub Actions 工作流</li><li>安装依赖</li><li>执行构建命令</li><li>将构建产物发布到 Pages 分支或 Pages 环境</li></ol><p>如果站点部署在仓库子路径，需要根据 Valaxy 文档配置对应的站点路径；如果使用自定义域名，通常可以保持根路径部署。</p><h2 id="netlify" tabindex="-1">Netlify <a class="header-anchor" href="#netlify" aria-label="Permalink to “Netlify”">​</a></h2><p>Netlify 部署时通常填写：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Build command: pnpm build</span></span>
<span class="line"><span>Publish directory: dist</span></span></code></pre></div><p>实际产物目录以你的 Valaxy 项目构建结果为准。</p><h2 id="vercel" tabindex="-1">Vercel <a class="header-anchor" href="#vercel" aria-label="Permalink to “Vercel”">​</a></h2><p>Vercel 可以直接导入 Git 仓库。构建命令通常为：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>pnpm build</span></span></code></pre></div><p>输出目录根据 Valaxy 构建产物配置填写。</p><h2 id="cloudflare-pages" tabindex="-1">Cloudflare Pages <a class="header-anchor" href="#cloudflare-pages" aria-label="Permalink to “Cloudflare Pages”">​</a></h2><p>Cloudflare Pages 常用配置：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Build command: pnpm build</span></span>
<span class="line"><span>Build output directory: dist</span></span></code></pre></div><p>如果项目使用 pnpm，建议在平台环境变量中指定 pnpm 版本或启用 Corepack。</p><h2 id="更新后重新部署" tabindex="-1">更新后重新部署 <a class="header-anchor" href="#更新后重新部署" aria-label="Permalink to “更新后重新部署”">​</a></h2><p>更新 Valaxy、主题或插件后，建议重新执行：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div><p>确认本地构建通过后再部署到生产环境。</p>`,38)])])}const g=i(t,[["render",n]]);export{k as __pageData,g as default};
